WITH C_INGRESOSCONSUMO AS (SELECT D_MOVIMIENTO.COMPANIA,   D_MOVIMIENTO.TIPOMOVIMIENTO,   TIPOMOVIMIENTO.CLASE,   TIPOMOVIMIENTO.TIPOELEMENTO,   SUM(D_MOVIMIENTO.VALORTOTAL) TOTAL,   TIPOMOVIMIENTO.NOMBRECORTO,   SUBSTR(D_MOVIMIENTO.ELEMENTO, 0, s$digitos$s) AGRUPACION,   D_MOVIMIENTO.FECHA,    TIPOMOVIMIENTO.CONCEPTO FROM D_MOVIMIENTO LEFT JOIN TIPOMOVIMIENTO ON D_MOVIMIENTO.COMPANIA        = TIPOMOVIMIENTO.COMPANIA AND D_MOVIMIENTO.TIPOMOVIMIENTO = TIPOMOVIMIENTO.CODIGO WHERE D_MOVIMIENTO.COMPANIA     = 's$compania$s' AND TIPOMOVIMIENTO.CLASE        = 's$clase$s' AND TIPOMOVIMIENTO.TIPOELEMENTO = 's$tipo$s' AND D_MOVIMIENTO.FECHA BETWEEN s$fechaInicial$s AND s$fechaFinal$s AND D_MOVIMIENTO.IND_REG NOT IN (0) GROUP BY D_MOVIMIENTO.COMPANIA,   D_MOVIMIENTO.TIPOMOVIMIENTO,   TIPOMOVIMIENTO.CLASE,   TIPOMOVIMIENTO.TIPOELEMENTO,   TIPOMOVIMIENTO.NOMBRECORTO,   SUBSTR(D_MOVIMIENTO.ELEMENTO, 0, s$digitos$s),   D_MOVIMIENTO.FECHA,   TIPOMOVIMIENTO.CONCEPTO,   D_MOVIMIENTO.IND_REG)    SELECT C_INGRESOSCONSUMO.COMPANIA, C_INGRESOSCONSUMO.TIPOMOVIMIENTO,           SUM(C_INGRESOSCONSUMO.TOTAL) TOTAL, C_INGRESOSCONSUMO.NOMBRECORTO,           C_INGRESOSCONSUMO.AGRUPACION, INVENTARIO.NOMBRELARGO,           C_INGRESOSCONSUMO.TIPOELEMENTO    FROM C_INGRESOSCONSUMO LEFT JOIN INVENTARIO       ON C_INGRESOSCONSUMO.COMPANIA = INVENTARIO.COMPANIA      AND C_INGRESOSCONSUMO.AGRUPACION = INVENTARIO.CODIGOELEMENTO    GROUP BY C_INGRESOSCONSUMO.COMPANIA, C_INGRESOSCONSUMO.TIPOMOVIMIENTO,          C_INGRESOSCONSUMO.NOMBRECORTO, C_INGRESOSCONSUMO.AGRUPACION,           INVENTARIO.NOMBRELARGO, C_INGRESOSCONSUMO.TIPOELEMENTO
